proof_block:
// The ensures of `det_thread_to_page` has the shape `P ==> Q`, where
// P is the conjunction of the original `thread_to_page` ensures applied
// once to r1 and once to r2.  The previous attempt failed because it
// tried to assert `r1.0 == thread_ptr` UNCONDITIONALLY — but the
// proof fn declares r1 / r2 as plain parameters with no per-run
// hypotheses, so that fact is only available under the antecedent.
//
// Wrap every observable-equality hint inside `if P { ... }` so each
// assert is checked under exactly the antecedent of the implication,
// then nudge z3 with view extensionality.
if (r1.0 == thread_ptr) && (r1.1@.is_init()) && (r1.1@.addr() == r1.0)
    && (r2.0 == thread_ptr) && (r2.1@.is_init()) && (r2.1@.addr() == r2.0)
{
    // First component: both equal thread_ptr, hence equal to each other.
    assert(r1.0 == thread_ptr);
    assert(r2.0 == thread_ptr);
    assert(r1.0 == r2.0);

    // Pull both `r1.1@` / `r2.1@` ensures into the local context so the
    // closed spec fns `addr()` / `is_init()` get instantiated for each
    // side; without this the two .@ terms carry disjoint triggers.
    assert(r1.1@.is_init());
    assert(r2.1@.is_init());
    assert(r1.1@.addr() == r1.0);
    assert(r2.1@.addr() == r2.0);

    // Observable equalities follow by transitivity through thread_ptr.
    assert(r1.1@.addr() == r2.1@.addr());
    assert(r1.1@.is_init() == r2.1@.is_init());

    // Sequence-style extensionality nudge on the PointsTo view: this
    // is exactly the structural equality lemma `=~=` invokes.
    assert(r1.1@ =~= r2.1@);
    assert(r1.1@ == r2.1@);

    // Close the goal explicitly so z3 sees the consequent at the end
    // of the `if` branch (the only branch where it has to hold).
    assert(det_thread_to_page_equal(r1, r2));
}
